-- Violates 1NF: multiple phone numbers in one column
CREATE TABLE violates_1nf (
  employee_id INT,
  name VARCHAR(100),
  phone_numbers VARCHAR(200)  -- '555-0100,555-0101,555-0102'
);

-- 1NF Compliant: separate row per phone number
CREATE TABLE employee_phones (
  employee_id INT,
  phone_number VARCHAR(20),
  PRIMARY KEY (employee_id, phone_number)
);

-- Before normalization: transitive dependency
