-- ERD concept translated to SQL
-- Customer ||---O< Order (one customer has many orders)

CREATE TABLE customers (
  customer_id INT PRIMARY KEY,
  name VARCHAR(100)
);

CREATE TABLE orders (
  order_id INT PRIMARY KEY,
  customer_id INT NOT NULL,
  FOREIGN KEY (customer_id) REFERENCES customers(customer_id)
);

examples.sql:
-- One Department has many Employees (1:N)
-- Visual: Department ||---O< Employee
-- (| = one, O = zero, < = many/crow's foot)

CREATE TABLE departments (
  dept_id INT PRIMARY KEY,
  dept_name VARCHAR(50)
);

CREATE TABLE employees (
  emp_id INT PRIMARY KEY,
  emp_name VARCHAR(100),
  dept_id INT,  -- can be NULL (optional participation)
  FOREIGN KEY (dept_id) REFERENCES departments(dept_id)
);

-- Students >---O< Courses (M:N)
-- Visual: Student >---O< Course
-- (> and < are crow's feet on both sides = many-to-many)

CREATE TABLE students (
  student_id INT PRIMARY KEY,
  name VARCHAR(100)
);

CREATE TABLE courses (
  course_id INT PRIMARY KEY,
  title VARCHAR(100)
);

-- Junction table resolves M:N into two 1:N relationships
CREATE TABLE enrollments (
  student_id INT REFERENCES students(student_id),
  course_id INT REFERENCES courses(course_id),
  enrollment_date DATE,
  PRIMARY KEY (student_id, course_id)
);

common_mistakes.error_sql:
