  customer_id INT PRIMARY KEY,
  order_id INT REFERENCES orders(order_id)  -- WRONG
);

common_mistakes.fix_sql:
-- Correct: foreign key goes on the 'many' side
CREATE TABLE orders (
  order_id INT PRIMARY KEY,
  customer_id INT REFERENCES customers(customer_id)
);

