START TRANSACTION;

-- Deduct from sender
UPDATE accounts SET balance = balance - 500 WHERE account_id = 101;

-- Add to receiver
UPDATE accounts SET balance = balance + 500 WHERE account_id = 202;

-- Verify both accounts exist and have valid balances
IF ROW_COUNT() = 1 THEN
    COMMIT;
ELSE
    ROLLBACK;
END IF;

START TRANSACTION;

-- Create the order
INSERT INTO orders (customer_id, order_date, total) VALUES (5, CURDATE(), 150.00);
SET @order_id = LAST_INSERT_ID();

-- Add order items
INSERT INTO order_items (order_id, product_id, quantity, price)
VALUES (@order_id, 101, 2, 50.00), (@order_id, 102, 1, 50.00);

-- Update inventory
UPDATE products SET stock = stock - 2 WHERE product_id = 101;
UPDATE products SET stock = stock - 1 WHERE product_id = 102;

COMMIT;

START TRANSACTION;

INSERT INTO orders (customer_id) VALUES (1);
SET @order_id = LAST_INSERT_ID();

SAVEPOINT after_order_created;

INSERT INTO order_items (order_id, product_id) VALUES (@order_id, 5);

-- Oops, wrong product - rollback just this part
ROLLBACK TO SAVEPOINT after_order_created;

INSERT INTO order_items (order_id, product_id) VALUES (@order_id, 6);
COMMIT;

